import { DtDateTime } from '../../../../core/dt-date/DtDateTime.js';

// Regex for validating IPV4 addresses
// https://regex101.com/r/kBFJ4C/1
const IS_IPV4_ADDRESS_REGEX = /^((25[0-5]|(2[0-4]|1\d|[1-9]|)\d)\.?\b){4}$/;

// Regex for validating IPV6 addresses
// https://regex101.com/r/cbxgms/1
const IS_IPV6_ADDRESS_REGEX =
  /^((?:[0-9A-Fa-f]{1,4}:){7}[0-9A-Fa-f]{1,4}|(?:[0-9A-Fa-f]{1,4}:){1,7}:|:(?::[0-9A-Fa-f]{1,4}){1,7}|(?:[0-9A-Fa-f]{1,4}:){1,6}:[0-9A-Fa-f]{1,4}|(?:[0-9A-Fa-f]{1,4}:){1,5}(?::[0-9A-Fa-f]{1,4}){1,2}|(?:[0-9A-Fa-f]{1,4}:){1,4}(?::[0-9A-Fa-f]{1,4}){1,3}|(?:[0-9A-Fa-f]{1,4}:){1,3}(?::[0-9A-Fa-f]{1,4}){1,4}|(?:[0-9A-Fa-f]{1,4}:){1,2}(?::[0-9A-Fa-f]{1,4}){1,5}|[0-9A-Fa-f]{1,4}:(?:(?::[0-9A-Fa-f]{1,4}){1,6})|:(?:(?::[0-9A-Fa-f]{1,4}){1,6}))$/;

// Regex for validating SmartscapeIds
// Matches <any word character>-<16-digit-hex-number> (DISK_1-000392498B505BD0)
// https://regex101.com/r/eA75AN/1
const IS_SMARTSCAPEID_REGEX = /^\w+-[0-9A-F]{16}$/;

// Regex for validating UIDs (64-bit and 128-bit identifiers)
// Matches 16 hexadecimal characters (64-bit) or 32 hexadecimal characters (128-bit)
// https://docs.dynatrace.com/docs/platform/grail/dynatrace-query-language/functions/conversion-and-casting-functions#uid64.
// https://regex101.com/r/iGrGrb/1
const IS_UID_REGEX = /^[0-9A-Fa-f]{16}$|^[0-9A-Fa-f]{32}$/;

/**
 * Checks whether the value is a valid ipv4 or ipv6 ipaddress.
 * @internal
 */
export function isValidIPAddress(value: string): boolean {
  const isValidIPv4 = new RegExp(IS_IPV4_ADDRESS_REGEX).exec(value);
  const isValidIPv6 = new RegExp(IS_IPV6_ADDRESS_REGEX).exec(value);

  return isValidIPv4 || isValidIPv6 ? true : false;
}

/**
 * Checks whether the value is a valid SmartscapeId.
 * @internal
 */
export function isValidSmartscapeId(value: string): boolean {
  return new RegExp(IS_SMARTSCAPEID_REGEX).test(value);
}

/**
 * Checks whether the value is a valid timestamp.
 * @internal
 */
export function isValidTimestamp(value: string): boolean {
  try {
    new DtDateTime(value);
    return true;
  } catch {
    return false;
  }
}

/**
 * Checks whether the value is a valid UID (Dynatrace entity ID).
 * @internal
 */
export function isValidUID(value: string): boolean {
  return new RegExp(IS_UID_REGEX).test(value);
}
